class Solution:
    def letterCasePermutation(self, s):
        letters = [i for i, ch in enumerate(s) if ch.isalpha()]
        m = len(letters)
        res = []
        for mask in range(1 << m):
            chars = list(s.lower())
            for b, idx in enumerate(letters):
                if mask & (1 << b):
                    chars[idx] = chars[idx].upper()
            res.append(''.join(chars))
        return res

