class Solution:
    def letterCasePermutation(self, s):
        res = []
        n = len(s)
        def rec(i, acc):
            if i == n:
                res.append(''.join(acc))
                return
            ch = s[i]
            if ch.isalpha():
                rec(i + 1, acc + [ch.lower()])
                rec(i + 1, acc + [ch.upper()])
            else:
                rec(i + 1, acc + [ch])
        rec(0, [])
        return res

