var letterCasePermutation = function(s) {
    const res = [];
    const n = s.length;
    function rec(i, acc) {
        if (i === n) {
            res.push(acc);
            return;
        }
        const ch = s[i];
        if (/[a-zA-Z]/.test(ch)) {
            rec(i + 1, acc + ch.toLowerCase());
            rec(i + 1, acc + ch.toUpperCase());
        } else {
            rec(i + 1, acc + ch);
        }
    }
    rec(0, '');
    return res;
};
